server/tests/helpers.py :: solid_raster
def solid_raster(width: int, height: int, red: int, green: int, blue: int) -> Raster:
    data = bytearray(width * height * 3)
    for index in range(0, len(data), 3):
        data[index] = red
        data[index + 1] = green
        data[index + 2] = blue
    return Raster(width, height, 3, data)

server/tests/helpers.py :: gradient_raster
def gradient_raster(width: int, height: int) -> Raster:
    data = bytearray(width * height * 3)
    for row in range(height):
        for col in range(width):
            index = (row * width + col) * 3
            data[index] = (col * 255) // max(1, width - 1)
            data[index + 1] = (row * 255) // max(1, height - 1)
            data[index + 2] = ((col + row) * 255) // max(1, width + height - 2)
    return Raster(width, height, 3, data)

server/tests/helpers.py :: rgba_checkerboard
def rgba_checkerboard(width: int, height: int, cell: int = 8) -> Raster:
    data = bytearray(width * height * 4)
    for row in range(height):
        for col in range(width):
            index = (row * width + col) * 4
            light = ((row // cell) + (col // cell)) % 2 == 0
            value = 240 if light else 30
            data[index : index + 3] = bytes((value, value, value))
            data[index + 3] = 200 if light else 80
    return Raster(width, height, 4, data)

